import React, { useState, useEffect } from 'react';

const Trips = () => {
  const [itinerary, setItinerary] = useState([]);

  useEffect(() => {
    loadItinerary();
  }, []);

  const loadItinerary = () => {
    const saved = JSON.parse(localStorage.getItem('itinerary') || '[]');
    setItinerary(saved);
  };

  const removeFromItinerary = (placeId) => {
    const updated = itinerary.filter(place => place.id !== placeId);
    setItinerary(updated);
    localStorage.setItem('itinerary', JSON.stringify(updated));
  };

  const getTotalCost = () => {
    return itinerary.reduce((total, place) => total + parseFloat(place.price), 0);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Itinerary</h1>
        {itinerary.length > 0 && (
          <div style={styles.totalCost}>Total: NPR {getTotalCost()}</div>
        )}
      </div>

      {itinerary.length === 0 ? (
        <div style={styles.noTrips}>
          <h3>No places in itinerary</h3>
          <p>Start exploring places to add to your itinerary!</p>
          <a href="/places" style={styles.exploreButton}>Explore Places</a>
        </div>
      ) : (
        <div style={styles.tripsGrid}>
          {itinerary.map(place => (
            <div key={place.id} style={styles.tripCard}>
              {place.image_url && (
                <img 
                  src={`http://localhost:5000${place.image_url}`} 
                  alt={place.name}
                  style={styles.placeImage}
                />
              )}
              <h3 style={styles.tripName}>{place.name}</h3>
              <p style={styles.cityName}>{place.city_name}</p>
              <p style={styles.tripBudget}>NPR {place.price}</p>
              <button 
                onClick={() => removeFromItinerary(place.id)}
                style={styles.removeButton}
              >
                Remove
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  totalCost: {
    fontSize: '1.5rem',
    fontWeight: '700',
    color: '#059669'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: 0
  },
  noTrips: {
    textAlign: 'center',
    padding: '3rem',
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  exploreButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    padding: '0.75rem 1.5rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    display: 'inline-block',
    marginTop: '1rem'
  },
  tripsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem'
  },
  tripCard: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  tripName: {
    fontSize: '1.25rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: '0 0 1rem 0'
  },
  tripBudget: {
    color: '#059669',
    fontWeight: '600',
    margin: '0 0 0.5rem 0'
  },
  tripDate: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: 0
  },
  placeImage: {
    width: '100%',
    height: '150px',
    objectFit: 'cover',
    borderRadius: '8px',
    marginBottom: '1rem'
  },
  cityName: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0 0 0.5rem 0'
  },
  removeButton: {
    backgroundColor: '#ef4444',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: '600',
    width: '100%',
    marginTop: '1rem'
  }
};

export default Trips;
